class Player(val name: String) {
    var startingHealth = 100

    // This runs immediately upon creation
    init {
        println("Spawning player: $name")
        if (name == "Boss") {
             startingHealth = 1000
        }
    }
}

fun main() {
    val p1 = Player("Bob")  // Prints: Spawning player: Bob
    val p2 = Player("Boss") // Prints: Spawning player: Boss
}
